import{_ as a,o as t,c as b,j as r,a as p,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"宝可梦技能—电","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—电.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—电.md"}'),n={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—电.md"};function s(o,e,_,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"宝可梦技能—电",tabindex:"-1"},[p("宝可梦技能—电 "),r("a",{class:"header-anchor",href:"#宝可梦技能—电","aria-label":'Permalink to "宝可梦技能—电"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004D")])])],-1),d('<h1 id="宝可梦技能—电-1" tabindex="-1">宝可梦技能—电 <a class="header-anchor" href="#宝可梦技能—电-1" aria-label="Permalink to &quot;宝可梦技能—电&quot;">​</a></h1><p>宝可梦技能—电<br> 特别说明：电系技能中物理系技能造成的伤害均为物理伤害。法伤技能造成的均为电击伤害。<br> 所有电系技能皆具有【法破】特性，不在每项技能中赘述。</p><p>雷电拳 C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：电系物理技能，该宝可梦进行一次近战攻击检定造成钝击伤害，这次攻击附带6dp雷电能量加值和1点来自于技艺的附加成功并具有【高速5】，这次攻击命中后会造成2点不可豁免的麻痹点数（创伤来源）。<br> 差价升级至B+2000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：攻击附带雷电能量加值提升至8dp，麻痹点数（创伤来源）提升至4，高速提升至10，并具有【接触攻击】特性。</p><p>电击 D+500<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：电系法伤技能，该宝可梦进行一次施法攻击检定，射程15米。攻击命中后会附带2点不可豁免的麻痹点数（环境来源）。<br> 差价升级至C+1000<br> 差价升级后仍可使用技艺的较低级别版本。<br> C级效果：攻击命中后附带的麻痹点数（环境来源）提升至4，射程提升至30米。</p><p>伏特替换 C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：电系法伤技能，该宝可梦进行一次施法攻击检定，这次攻击具有9dp的技艺加值，【高速5】和1点附加成功，射程25米。本次攻击命中后，该宝可梦可与你任意一个还在精灵球中的宝可梦进行替换，替换后的宝可梦这一回合内的剩余动作与替换前宝可梦的剩余动作相同。<br> 差价升级至B+2000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：本次攻击的射程提升至60米，高速提升至10，并额外具有【接触攻击】、【能量武器特性】。</p><p>电网 B+3000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：电系法伤技能，该宝可梦进行一次施法攻击检定，这次攻击提升9dp攻击检定的雷电能量加值。这次攻击射程为85米扇形范围内的所有敌方单位，反射豁免。命中敌人后将使敌人的先攻权下降24点（最低降至1点）。该效果持续1轮。敌人可以通过离开该范围来免疫该次效果。</p><p>十万伏特 C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：电系法伤技能，该宝可梦进行一次施法攻击检定，这次攻击检定+9dp的雷电能量加值，射程30米。这次攻击额外具有10高速和5破魔的特性。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：这次攻击射程提升至90米，获得【能量武器】【8加骰】【湮灭】特性。攻击命中后附带伤害值一半的麻痹点数（环境来源），正常豁免。<br> A级效果：这次攻击攻击检定附带的雷电能量加值提升为该宝可梦的施法属性值，射程提升至敏感范围，攻击命中后附带的麻痹点数（环境来源）提升为等同于伤害值，正常豁免。本次攻击忽略对手的盔甲、天生防御，这是一个A级的环境来源效果。</p><p>打雷 A+4000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：电系法伤技能，该宝可梦进行一次施法攻击检定，这次攻击具有等同于该宝可梦施法属性的雷电能量加值，射程355米。这次攻击具有【8加骰】，【湮灭】特性，忽略对手的盔甲、闪避防御，这是一个A级的环境来源效果。</p><p>放电 B+2000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 电系法伤技能，该宝可梦进行一次施法攻击检定，这次攻击具有3点来自于技艺的附加成功。这是一个对周围所有敌人的范围攻击，以自身为圆心半径90米，反射豁免。攻击附带等于伤害值一半的麻痹点数（环境来源），正常豁免。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(n,[["render",s]]);export{f as __pageData,m as default};
